class MyCustomJSONHandler(json.JSONEncoder):
    def default(self, obj: object) -> object:
        if isinstance(obj, np.ndarray):
            nan_mask = np.isnan(obj)
            non_nan = obj[~nan_mask]
            # Get unique non-NaN values (np.unique deduplicates)
            non_nan_unique = np.unique(non_nan) if non_nan.size > 0 else np.array([])
            # Keep each NaN as a separate value
            nan_count = int(np.sum(nan_mask))
            result = np.concatenate([
                non_nan_unique,
                np.full(nan_count, np.nan)
            ])
            return result.tolist()
        return super().default(obj)

